The problem seems to be in the native library:

    void xtables_save_string(const char *value)
    {
    	static const char no_quote_chars[] = "_-0123456789"
    		"abcdefghijklmnopqrstuvwxyz"
    		"ABCDEFGHIJKLMNOPQRSTUVWXYZ";
    	static const char escape_chars[] = "\"\\'";
    	size_t length;
    	const char *p;
    
    	length = strspn(value, no_quote_chars);
    	if (length > 0 && value[length] == 0) {
    		/* no quoting required */
    		putchar(' ');
    		fputs(value, stdout);
    	} else {
    		/* there is at least one dangerous character in the
    		   value, which we have to quote.  Write double quotes
    		   around the value and escape special characters with
    		   a backslash */
    		printf(" \"");
    
    		for (p = strpbrk(value, escape_chars); p != NULL;
    		     p = strpbrk(value, escape_chars)) {
    			if (p > value)
    				fwrite(value, 1, p - value, stdout);
    			putchar('\\');
    			putchar(*p);
    			value = p + 1;
    		}
    
    		/* print the rest and finish the double quoted
    		   string */
    		fputs(value, stdout);
    		putchar('\"');
    	}
    }

It quotes the characters `"`, `\` and `'`. Let me think about a workaround here.

An early example of an alternative implementation which works faster:

```
def username(template=None) -> str:
    name = choice(USERNAMES)
    date = randint(1800, 2070)

    templates = ('U_d', 'U.d', 'U-d', 'ld', 'l-d', 'Ud',
                 'l.d', 'l_d', 'default')

    if template is None:
        template = choice(templates)

    if template not in templates:
        raise KeyError()

    if template == 'Ud':
        return '{}{}'.format(name.capitalize(), date)
    elif template == 'U.d':
        return '{}.{}'.format(name.capitalize(), date)
    elif template == 'ld':
        return '{}{}'.format(name, date)
    elif template == 'U-d':
        return '{}-{}'.format(name.title(), date)
    elif template == 'U_d':
        return '{}_{}'.format(name.title(), date)
    elif template == 'l-d':
        return '{}-{}'.format(name, date)
    elif template == 'l_d':
        return '{}_{}'.format(name, date)

    return '{}.{}'.format(name, date)
```

