Per the documentation, a slightly [different decoration scheme](https://cloud.google.com/endpoints/docs/frameworks/python/create_api#creating_an_api_implemented_with_multiple_classes) must be used when implementing across multiple classes.

In your case, it would be similar to as follows:

```py
import endpoints
from protorpc import message_types, remote


api_collection = endpoints.api(name='myapi',
    version='v1',
    [AUTH SETTINGS]
)

@api_collection.api_class(resource_name='someapi', path='someapi')
class SomeApiService(remote.Service):

    @endpoints.method(
        message_types.VoidMessage,
        message_types.VoidMessage,
        path='someaction',
        http_method='GET',
        name='someaction',
    )
    def someaction(self, request):
        return message_types.VoidMessage()


@api_collection.api_class(resource_name='anotherapi', path='anotherapi')
class AnotherApiService(remote.Service):

    @endpoints.method(
        message_types.VoidMessage,
        message_types.VoidMessage,
        path='anotheraction',
        http_method='GET',
        name='anotheraction',
    )
    def anotheraction(self, request):
        return message_types.VoidMessage()


APPLICATION = endpoints.api_server([api_collection])
```

